def compress_a_string_with_counts(s):
    if not s:
        return ''
    parts = []
    current = s[0]
    count = 0
    for ch in s:
        if ch == current:
            count += 1
        else:
            parts.append(current + str(count))
            current = ch
            count = 1
    parts.append(current + str(count))
    return ''.join(parts)

