solutionCode:
def implement_a_simple_lru_cache(operations, capacity):
    cache = {}
    order = []
    output = []
    for op in operations:
        if op[0] == 'put':
            _, key, value = op
            if key in cache:
                order.remove(key)
            elif len(order) >= capacity:
                oldest = order.pop(0)
                del cache[oldest]
            cache[key] = value
            order.append(key)
            output.append(None)
        else:
            _, key = op
            if key not in cache:
                output.append(-1)
            else:
                order.remove(key)
                order.append(key)
                output.append(cache[key])
    return output

